import { Telegraf } from 'telegraf';
import winston from 'winston';
import { v4 as uuidv4 } from 'uuid';
import { Config } from '../config/env';

const bot = new Telegraf(Config.TELEGRAM_BOT_TOKEN);

// Configure logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'NotificationDispatcher' },
  transports: [
    new winston.transports.Console({
      format: winston.format.simple(),
    }),
  ],
});

export class NotificationDispatcher {
  public async dispatchMessage(chatId: string, message: string): Promise<void> {
    const requestId = uuidv4();
    try {
      await bot.telegram.sendMessage(chatId, message);
      logger.info('Message sent successfully', { requestId });
    } catch (error) {
      logger.error('Failed to send message', { error, requestId });
      // Implement retry logic if necessary
    }
  }
}

// Set up the bot to handle incoming messages
bot.start((ctx) => ctx.reply('Welcome! The Notification Dispatcher is now live.'));

bot.launch();

process.once('SIGINT', () => bot.stop('SIGINT'));
process.once('SIGTERM', () => bot.stop('SIGTERM'));

import { z } from 'zod';

export const envSchema = z.object({
  TELEGRAM_BOT_TOKEN: z.string().nonempty(),
  CORS_ORIGIN: z.string().nonempty(),
});

export const Config = envSchema.parse(process.env);
